import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input, Badge, Tag, Avatar } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  Search,
  Plus,
  Edit3,
  Trash2,
  Truck,
  Users,
  ShieldCheck,
  Activity,
} from "lucide-react";
import {
  fetchDeliveryBoys,
  deleteDeliveryBoy,
} from "../features/delivery/deliveryBoySlice";
import CustomModal from "../components/CustomModal";

const DeliveryBoyList = () => {
  const [open, setOpen] = useState(false);
  const [boyId, setBoyId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setBoyId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  const { deliveryBoys, isLoading } = useSelector((state) => state.deliveryBoy);

  useEffect(() => {
    dispatch(fetchDeliveryBoys());
  }, [dispatch]);

  const handleDelete = (id) => {
    dispatch(deleteDeliveryBoy(id));
    setOpen(false);
  };

  const columns = [
    {
      title: "#",
      dataIndex: "key",
      width: 80,
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-slate-400 bg-slate-50 px-2 py-1 rounded-md">
          AGNT-{text}
        </span>
      ),
    },
    {
      title: "AGENT",
      dataIndex: "name",
      render: (_, record) => (
        <div className="flex items-center gap-3">
          <Avatar
            size={36}
            src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${record.firstname}`}
            className="rounded-xl ring-1 ring-slate-100"
          />
          <div>
            <span className="font-black text-slate-900 tracking-tight text-xs block">
              {record.firstname} {record.lastname}
            </span>
            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">
              Field Agent
            </span>
          </div>
        </div>
      ),
      sorter: (a, b) => a.firstname.localeCompare(b.firstname),
    },
    {
      title: "EMAIL",
      dataIndex: "email",
      render: (text) => (
        <span className="text-slate-500 font-medium text-[11px]">{text}</span>
      ),
    },
    {
      title: "MOBILE",
      dataIndex: "mobile",
      render: (text) => (
        <span className="text-slate-500 font-medium text-[11px]">{text}</span>
      ),
    },
    {
      title: "STATUS",
      render: () => (
        <Tag
          color="success"
          className="rounded-full text-[10px] font-black uppercase tracking-widest"
        >
          Active
        </Tag>
      ),
    },
    {
      title: "ACTIONS",
      dataIndex: "action",
      render: (_, record) => (
        <Space size="middle">
          <Link to={`/admin/delivery-boys/edit/${record._id}`}>
            <Button
              type="text"
              icon={<Edit3 size={16} />}
              className="text-slate-400 hover:text-blue-600 rounded-xl"
            />
          </Link>
          <Button
            type="text"
            danger
            icon={<Trash2 size={16} />}
            onClick={() => showModal(record._id)}
            className="rounded-xl"
          />
        </Space>
      ),
    },
  ];

  const data1 =
    deliveryBoys
      ?.filter(
        (b) =>
          !searchText ||
          b.firstname.toLowerCase().includes(searchText.toLowerCase()) ||
          b.lastname.toLowerCase().includes(searchText.toLowerCase()) ||
          b.email.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((boy, i) => ({
        ...boy,
        key: i + 1,
      })) || [];

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Truck size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              Logistics Agent Registry
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Users size={12} /> {data1.length} Active Agents
            </span>
            <span className="flex items-center gap-2 text-[10px] font-black text-emerald-600 bg-emerald-50 border border-emerald-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Activity size={12} /> System Active
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <div className="relative">
            <Search
              className="absolute top-1/2 left-4 -translate-y-1/2 text-slate-300"
              size={16}
            />
            <Input
              placeholder="Search agents..."
              className="pl-11 rounded-2xl border-slate-100 w-64 h-11 font-medium text-xs"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to="/admin/createdelivery">
            <Button
              type="primary"
              size="large"
              icon={<Plus size={16} />}
              className="bg-[#257CB7] rounded-2xl h-11 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none flex items-center gap-2"
            >
              Register Agent
            </Button>
          </Link>
        </div>
      </div>

      {/* Table Card */}
      <div className="enterprise-card bg-white p-4 border-none shadow-2xl shadow-slate-200/40">
        <Table
          columns={columns}
          dataSource={data1}
          loading={isLoading}
          pagination={{ pageSize: 12 }}
          className="enterprise-table"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => handleDelete(boyId)}
        title="Confirm Agent Removal"
        content="This action will deactivate the logistics agent. Active delivery assignments may be affected."
      />
    </div>
  );
};

export default DeliveryBoyList;
